package com.chaobo.scm.supplier.infrastructure.persistence.quote;import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.quote.*;import com.chaobo.scm.supplier.domain.quote.*;import org.springframework.stereotype.Repository;import java.util.*;
@Repository public class MyBatisSupplierQuoteRepository implements SupplierQuoteRepository,SupplierQuoteReadModelPort{private final SupplierQuoteMapper mapper;public MyBatisSupplierQuoteRepository(SupplierQuoteMapper mapper){this.mapper=mapper;}public List<Long> expiredIds(){return mapper.expiredIds();}public Optional<SupplierQuoteAggregate> findById(long id){var quote=mapper.quote(id);return quote==null?Optional.empty():Optional.of(aggregate(quote));}public void save(SupplierQuoteAggregate aggregate,long operator){var quote=row(aggregate);if(mapper.quote(aggregate.id())==null){mapper.insert(quote,operator);for(var line:aggregate.lines())mapper.insertLine(line(aggregate.id(),line));return;}if(mapper.update(quote,aggregate.version()-1,operator)!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"供应商报价已被更新");var existing=mapper.lines(aggregate.id()).stream().map(SupplierQuoteMapper.LineRow::id).collect(java.util.stream.Collectors.toSet());var retained=new ArrayList<Long>();for(var line:aggregate.lines()){var row=line(aggregate.id(),line);retained.add(line.lineId());if(existing.contains(line.lineId()))mapper.updateLine(row);else mapper.insertLine(row);}mapper.deleteMissingLines(aggregate.id(),retained);}public Optional<SupplierQuoteView> detail(long id){var quote=mapper.quote(id);return quote==null?Optional.empty():Optional.of(view(quote));}public PageResult<SupplierQuoteView> page(Long supplierId,Integer status,String keyword,int page,int size){return new PageResult<>(page,size,mapper.count(supplierId,status,keyword),mapper.page(supplierId,status,keyword,(page-1)*size,size).stream().map(this::view).toList());}private SupplierQuoteAggregate aggregate(SupplierQuoteMapper.QuoteRow quote){return SupplierQuoteAggregate.rehydrate(quote.id(),quote.no(),quote.supplierId(),quote.rfqId(),quote.rfqNo(),quote.currency(),quote.from(),quote.to(),quote.status(),quote.reason(),quote.ref(),mapper.lines(quote.id()).stream().map(this::line).toList(),quote.version());}private SupplierQuoteMapper.QuoteRow row(SupplierQuoteAggregate aggregate){return new SupplierQuoteMapper.QuoteRow(aggregate.id(),aggregate.no(),aggregate.supplierId(),aggregate.rfqId(),aggregate.rfqNo(),aggregate.currency(),aggregate.validFrom(),aggregate.validTo(),aggregate.status().code(),aggregate.rejectionReason(),aggregate.agreementRef(),aggregate.version());}private SupplierQuoteMapper.LineRow line(long quoteId,QuoteLine line){return new SupplierQuoteMapper.LineRow(line.lineId(),quoteId,line.skuCode(),line.quoteQty(),line.unitPrice(),line.taxRate(),line.deliveryDays(),line.moq());}private QuoteLine line(SupplierQuoteMapper.LineRow row){return new QuoteLine(row.id(),row.sku(),row.qty(),row.price(),row.tax(),row.days(),row.moq());}private SupplierQuoteView view(SupplierQuoteMapper.QuoteRow quote){var status=QuoteStatus.fromCode(quote.status());return new SupplierQuoteView(quote.id(),quote.no(),quote.supplierId(),quote.rfqId(),quote.rfqNo(),quote.currency(),quote.from(),quote.to(),status.code(),status.label(),quote.reason(),quote.ref(),quote.version(),mapper.lines(quote.id()).stream().map(row->new SupplierQuoteView.Line(row.id(),row.sku(),row.qty(),row.price(),row.tax(),row.days(),row.moq())).toList());}}
